// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

contract TokenMarketingBounty is ReentrancyGuard {
    using SafeERC20 for IERC20;

    IERC20 public immutable rewardToken;
    address public immutable admin;
    mapping(address => uint256) public rewards;
    uint256 public totalRewards;

    event RewardsClaimed(address indexed user, uint256 amount);

    constructor(address _rewardToken, address _admin) {
        require(_rewardToken != address(0), "Invalid reward token address");
        require(_admin != address(0), "Invalid admin address");
        rewardToken = IERC20(_rewardToken);
        admin = _admin;
    }

    modifier onlyAdmin() {
        require(msg.sender == admin, "Not admin");
        _;
    }

    function addRewards(address user, uint256 amount) external onlyAdmin {
        require(amount > 0, "Amount must be greater than 0");
        rewards[user] += amount;
        totalRewards += amount;
    }

    function claimRewards() external nonReentrant {
        uint256 reward = rewards[msg.sender];
        require(reward > 0, "No rewards to claim");

        rewards[msg.sender] = 0;
        totalRewards -= reward;

        rewardToken.safeTransfer(msg.sender, reward);
        emit RewardsClaimed(msg.sender, reward);
    }

    function getRemainingRewards(address user) external view returns (uint256) {
        return rewards[user];
    }

    function getTotalRewards() external view returns (uint256) {
        return totalRewards;
    }
}
