// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "forge-std/Test.sol";
import "../TokenMarketingBounty.sol";

contract TokenMarketingBountyTest is Test {
    TokenMarketingBounty bounty;
    IERC20 rewardToken;
    address admin = address(1);
    address user1 = address(2);
    address user2 = address(3);

    function setUp() public {
        rewardToken = IERC20(address(new MockERC20("RewardToken", "RTK", 18)));
        bounty = new TokenMarketingBounty(address(rewardToken), admin);

        // Mint some tokens to admin for distribution
        rewardToken.mint(admin, 1000 ether);
        rewardToken.safeTransfer(address(bounty), 1000 ether);
    }

    function testAddRewards() public {
        bounty.addRewards(user1, 100 ether);
        assertEq(bounty.getRemainingRewards(user1), 100 ether);
        assertEq(bounty.getTotalRewards(), 100 ether);
    }

    function testClaimRewards() public {
        bounty.addRewards(user1, 100 ether);
        vm.prank(user1);
        bounty.claimRewards();
        assertEq(bounty.getRemainingRewards(user1), 0);
        assertEq(bounty.getTotalRewards(), 0);
        assertEq(rewardToken.balanceOf(user1), 100 ether);
    }

    function testReentrancyGuard() public {
        bounty.addRewards(user1, 100 ether);
        vm.prank(user1);
        vm.expectRevert("ReentrancyGuard: reentrant call");
        bounty.claimRewards();
    }

    function testClaimRewardsMultipleUsers() public {
        bounty.addRewards(user1, 100 ether);
        bounty.addRewards(user2, 200 ether);

        vm.prank(user1);
        bounty.claimRewards();
        assertEq(bounty.getRemainingRewards(user1), 0);
        assertEq(rewardToken.balanceOf(user1), 100 ether);

        vm.prank(user2);
        bounty.claimRewards();
        assertEq(bounty.getRemainingRewards(user2), 0);
        assertEq(rewardToken.balanceOf(user2), 200 ether);
    }
}

contract MockERC20 is ERC20 {
    constructor(string memory name, string memory symbol, uint8 decimals) ERC20(name, symbol) {
        _mint(msg.sender, 1000000 * 10 ** decimals);
    }

    function mint(address to, uint256 amount) external {
        _mint(to, amount);
    }
}
